import { LightningElement } from 'lwc';
import InfoPanel from './demo';
export default class InfoExample extends LightningElement {
    async handleOpenTooltip() {
        const button = this.template.querySelector('button');
        await InfoPanel.open({
            source: button,
            position: 'top center',
            popover: 'hint',
            message: 'This is an info panel.',
            minWidth: '5rem',
        });
    }
}
